const data = $input.first().json;
const vaga = data.vaga || {};
const top3 = data.top3 || [];
const empresa = $vars.EMPRESA_NOME || 'Empresa';
const EVOLUTION_URL = $vars.EVOLUTION_API_URL;
const EVOLUTION_KEY = $vars.EVOLUTION_API_KEY;
const EVOLUTION_INST = $vars.EVOLUTION_INSTANCE;
const SUPABASE_URL = $vars.SUPABASE_URL;
const SUPABASE_KEY = $vars.SUPABASE_KEY;
const PAINEL_URL = $vars.PAINEL_URL || 'https://painel.empresa.com';

async function sendWhatsApp(phone, message) {
  if (!phone || !EVOLUTION_URL) return;
  try {
    await fetch(`${EVOLUTION_URL}/message/sendText/${EVOLUTION_INST}`, {
      method: 'POST',
      headers: { 'apikey': EVOLUTION_KEY, 'Content-Type': 'application/json' },
      body: JSON.stringify({ number: phone.replace(/\D/g,'') + '@s.whatsapp.net', options: { delay: 1200, presence: 'composing' }, textMessage: { text: message } })
    });
  } catch(e) {}
}

// Mensagem WhatsApp para o recrutador
const medalhas = ['🥇', '🥈', '🥉'];
let candidatosTexto = '';
top3.forEach((c, i) => {
  const distKm = parseFloat(c.candidato_distancia_km || c._distancia_km || c.distancia_sede_km || 0).toFixed(1);
  const tempo = Math.round(distKm * 3);
  const habilidades = (c.habilidades_array || []).slice(0, 3).join(', ');
  candidatosTexto += `
${medalhas[i]} *${i+1}º COLOCADO* — Score: ${c.score_final}/100
👤 ${c.nome}
📍 ${distKm} km | ⏱️ ~${tempo} min
✅ ${c.formacao || 'N/A'} | ${c.anos_experiencia || 0} anos exp.
${habilidades ? '🔧 ' + habilidades : ''}
📞 ${c.whatsapp || c.telefone || 'N/A'} | ${c.email || 'N/A'}
`;
});

const mensagemRecrutador = `🎯 *SHORTLIST — ${vaga.titulo || 'Vaga'}*
━━━━━━━━━━━━━━━━━━━━━━
📊 *${data.total_avaliados || top3.length} candidatos avaliados*
${candidatosTexto}
🔗 ${PAINEL_URL}/vagas/${vaga.vaga_id || ''}
━━━━━━━━━━━━━━━━━━━━━━
_Responda:_
*APROVAR 1*, *APROVAR 2* ou *APROVAR 3*
*REPROVAR [nº]* para rejeitar
*CONTRATAR [nº]* para finalizar`;

// Enviar WhatsApp para recrutador
if (vaga.responsavel_whatsapp) {
  await sendWhatsApp(vaga.responsavel_whatsapp, mensagemRecrutador);
}

// Notificar candidatos do top 3
for (const c of top3) {
  if (c.whatsapp) {
    const msgCandidato = `🌟 Olá, *${c.nome}*!\n\nSeu perfil foi selecionado para a shortlist da vaga de *${vaga.titulo}* em ${empresa}! 🎉\n\n🏆 Você está em *${c.posicao_ranking}º lugar* — Score: *${c.score_final}/100*\n\n📅 Nossa equipe entrará em contato em até *48 horas* para agendamento de entrevista.\n\nMantenha seu WhatsApp disponível! ✅`;
    await sendWhatsApp(c.whatsapp, msgCandidato);
    // Atualiza notificado no Supabase
    if (vaga.vaga_id && c.id) {
      try {
        await fetch(`${SUPABASE_URL}/rest/v1/candidaturas?candidato_id=eq.${c.id}&vaga_id=eq.${vaga.vaga_id}`, {
          method: 'PATCH',
          headers: { 'apikey': SUPABASE_KEY, 'Authorization': `Bearer ${SUPABASE_KEY}`, 'Content-Type': 'application/json' },
          body: JSON.stringify({ notificado_candidato: true, data_notificacao: new Date().toISOString() })
        });
      } catch(e) {}
    }
  }
}

// Log analytics
try {
  await fetch(`${SUPABASE_URL}/rest/v1/analytics_triagem`, {
    method: 'POST',
    headers: { 'apikey': SUPABASE_KEY, 'Authorization': `Bearer ${SUPABASE_KEY}`, 'Content-Type': 'application/json' },
    body: JSON.stringify({ canal: 'output_shortlist', vaga_id: vaga.vaga_id, vaga_titulo: vaga.titulo, total_avaliados: data.total_avaliados, top3_scores: JSON.stringify(top3.map(c => ({id:c.id, score:c.score_final}))), created_at: new Date().toISOString() })
  });
} catch(e) {}

// Montar tabela comparativa para e-mail
const tabelaRows = top3.map((c, i) => {
  const distKm = parseFloat(c.candidato_distancia_km || c.distancia_sede_km || 0).toFixed(1);
  const bg = i === 0 ? '#e8f5e9' : (i === 1 ? '#e3f2fd' : '#fff3e0');
  const jus = c.justificativa || c.justificativa_ia || '';
  return `<tr style="background:${bg}"><td style="padding:8px;font-weight:bold">${medalhas[i]} ${i+1}º</td><td style="padding:8px">${c.nome}</td><td style="padding:8px;text-align:center"><strong>${c.score_final}</strong></td><td style="padding:8px;text-align:center">${c.score_tecnico||'-'}</td><td style="padding:8px;text-align:center">${c.score_geo||'-'}</td><td style="padding:8px">${distKm} km</td><td style="padding:8px">${c.whatsapp||c.telefone||'-'}</td></tr><tr style="background:${bg}"><td colspan="7" style="padding:4px 8px;font-style:italic;font-size:13px">💡 ${jus}</td></tr>`;
}).join('');

const emailHtml = `<!DOCTYPE html><html><head><meta charset="UTF-8"></head><body style="font-family:Arial,sans-serif;color:#333;max-width:700px;margin:0 auto;padding:20px">
<div style="background:#1a56db;color:white;padding:20px;border-radius:8px 8px 0 0"><h2>🎯 3 Candidatos Selecionados</h2><p>${vaga.titulo} | ${empresa} | ${new Date().toLocaleDateString('pt-BR')}</p></div>
<div style="background:#f8f9fa;padding:20px;border-radius:0 0 8px 8px">
<table style="width:100%;border-collapse:collapse;border:1px solid #ddd">
<tr style="background:#1a56db;color:white"><th style="padding:8px">Rank</th><th style="padding:8px">Nome</th><th style="padding:8px">Score</th><th style="padding:8px">Técnico</th><th style="padding:8px">Geo</th><th style="padding:8px">Distância</th><th style="padding:8px">Contato</th></tr>
${tabelaRows}
</table>
<p style="margin-top:20px"><a href="${PAINEL_URL}/vagas/${vaga.vaga_id||''}" style="background:#1a56db;color:white;padding:10px 20px;border-radius:4px;text-decoration:none">Ver Perfis Completos no Painel</a></p>
<p style="font-size:12px;color:#777">Total avaliados: ${data.total_avaliados||top3.length} | Gerado pelo Agente IA de Seleção</p>
</div></body></html>`;

return [{ json: { emailHtml, responsavel_email: vaga.responsavel_email, titulo: vaga.titulo, empresa, mensagemRecrutador, top3Notificados: top3.filter(c => c.whatsapp).length } }];
